public class ArrayComparison {
    public static void main(String[] args) {
        int[] arr1 = {3, 2, 5, 7};
        int[] arr2 = {2, 3, 5, 7};

        // Approach 1: Sort and compare — O(n log n)
        int[] sorted1 = arr1.clone();
        int[] sorted2 = arr2.clone();
        Arrays.sort(sorted1);
        Arrays.sort(sorted2);
        boolean same = Arrays.equals(sorted1, sorted2);
        System.out.println("Same (sort): " + same); // true

        // Approach 2: Frequency map — O(n)
        boolean sameFreq = hasSameElements(arr1, arr2);
        System.out.println("Same (freq): " + sameFreq); // true

        // Approach 3: Java 8 Streams
        boolean sameStream =
            arr1.length == arr2.length &&
            IntStream.of(arr1).boxed().sorted()
                .collect(Collectors.toList())
                .equals(IntStream.of(arr2).boxed().sorted()
                    .collect(Collectors.toList()));
        System.out.println("Same (stream): " + sameStream);
    }

    static boolean hasSameElements(int[] a, int[] b) {
        if (a.length != b.length) return false;
        Map<Integer, Integer> freq = new HashMap<>();
        for (int n : a) freq.merge(n, 1, Integer::sum);
        for (int n : b) {
            if (!freq.containsKey(n)) return false;
            int count = freq.get(n) - 1;
            if (count == 0) freq.remove(n);
            else freq.put(n, count);
        }
        return freq.isEmpty();
    }
}

import java.util.stream.*;

public class RemoveChar {
    public static void main(String[] args) {
        String input = "Hello World, Welcome!";
        char toRemove = 'l';

        // Approach 1: String.replace — simplest
        String result1 = input.replace(String.valueOf(toRemove), "");
        System.out.println(result1); // Heo Word, Wecome!

        // Approach 2: Java 8 Streams
        String result2 = input.chars()
            .filter(c -> c != toRemove)
            .collect(
                StringBuilder::new,
                (sb, c) -> sb.append((char) c),
                StringBuilder::append)
            .toString();
        System.out.println(result2); // Heo Word, Wecome!

        // Approach 3: StringBuilder — manual, most control
        StringBuilder sb = new StringBuilder();
        for (char c : input.toCharArray()) {
            if (c != toRemove) sb.append(c);
        }
        System.out.println(sb.toString());

        // Approach 4: Regex
        String result4 = input.replaceAll(
            Pattern.quote(String.valueOf(toRemove)), "");
        System.out.println(result4);

        // Count occurrences of character
        long count = input.chars()
            .filter(c -> c == toRemove)
            .count();
        System.out.println("'" + toRemove + "' appears " + count + " times");
    }
}

