public class FindSpecialChars {
    public static void main(String[] args) {
        String input = "Hello, World! @Java#2024.";

        // Approach 1: Stream with Character.isLetterOrDigit
        List<Character> specialChars = input.chars()
            .filter(c -> !Character.isLetterOrDigit(c))
            .mapToObj(c -> (char) c)
            .distinct()
            .collect(Collectors.toList());
        System.out.println("Special chars: " + specialChars);
        // [',', ' ', '!', ' ', '@', '#', '.']

        // Approach 2: Collect as String
        String specialOnly = input.chars()
            .filter(c -> !Character.isLetterOrDigit(c) && c != ' ')
            .collect(
                StringBuilder::new,
                (sb, c) -> sb.append((char) c),
                StringBuilder::append)
            .toString();
        System.out.println("Special: " + specialOnly); // ,!@#.

        // Approach 3: Regex — find all special chars
        String[] special = input.split("[a-zA-Z0-9\\s]");
        System.out.println(Arrays.toString(special));

        // Check if string contains special chars
        boolean hasSpecial = input.chars()
            .anyMatch(c -> !Character.isLetterOrDigit(c)
                       && !Character.isWhitespace(c));
        System.out.println("Has special chars: " + hasSpecial); // true

        // Count special chars
        long count = input.chars()
            .filter(c -> !Character.isLetterOrDigit(c)
                      && !Character.isWhitespace(c))
            .count();
        System.out.println("Count: " + count); // 4 (,!@#.)
    }
}

public class StringRotation {
    public static void main(String[] args) {
        System.out.println(isRotation("abcde", "cdeab")); // true
        System.out.println(isRotation("abcde", "abced")); // false
        System.out.println(isRotation("hello", "llohe")); // true
        System.out.println(isRotation("", ""));            // true
    }

    // Approach 1: Concatenation trick — O(n)
    public static boolean isRotation(String s1, String s2) {
        if (s1 == null || s2 == null) return false;
        if (s1.length() != s2.length()) return false;
        if (s1.isEmpty()) return true;
        // If s2 is rotation of s1, it must appear in s1+s1
        return (s1 + s1).contains(s2);
    }

    // Approach 2: Manual rotation check
    public static boolean isRotationManual(String s1, String s2) {
        if (s1.length() != s2.length()) return false;
        int n = s1.length();
        for (int i = 0; i < n; i++) {
            // Check if rotating s1 by i positions gives s2
            boolean match = true;
            for (int j = 0; j < n; j++) {
                if (s1.charAt((i + j) % n) != s2.charAt(j)) {
                    match = false;
                    break;
                }
            }
            if (match) return true;
        }
        return false;
    }

    // Approach 3: Java Streams version
    public static boolean isRotationStream(String s1, String s2) {
        if (s1.length() != s2.length()) return false;
        return (s1 + s1).indexOf(s2) != -1;
    }
}

import java.util.Arrays;
import java.util.stream.IntStream;

public class MissingNumber {
    public static void main(String[] args) {
        int[] arr = {1, 2, 4, 5, 6, 7, 8}; // Missing 3, N=8
        int n = 8;

        // Approach 1: Sum formula — most intuitive
        int expectedSum = n * (n + 1) / 2;
        int actualSum = 0;
        for (int num : arr) actualSum += num;
        System.out.println("Missing: " + (expectedSum - actualSum)); // 3

        // Approach 2: XOR — avoids overflow for large N
        int xor = 0;
        for (int i = 1; i <= n; i++) xor ^= i;
        for (int num : arr) xor ^= num;
        System.out.println("Missing (XOR): " + xor); // 3

        // Approach 3: Java 8 Streams
        int sumArray = Arrays.stream(arr).sum();
        int sumExpected = IntStream.rangeClosed(1, n).sum();
        System.out.println("Missing (Stream): " + (sumExpected - sumArray));

        // Approach 4: Sort and find gap — O(n log n)
        int[] sorted = arr.clone();
        Arrays.sort(sorted);
        for (int i = 0; i < sorted.length; i++) {
            if (sorted[i] != i + 1) {
                System.out.println("Missing (sort): " + (i + 1));
                break;
            }
        }

        // For unsorted array with unknown range
        // Use HashSet approach
        java.util.Set<Integer> set = new java.util.HashSet<>();
        for (int num : arr) set.add(num);
        for (int i = 1; i <= n; i++) {
            if (!set.contains(i)) {
                System.out.println("Missing (set): " + i);
            }
        }
    }
}

public class HalfCaseConversion {
    public static void main(String[] args) {
        System.out.println(convertHalf("HelloWorld"));
        // helloWORLD
        System.out.println(convertHalf("Java"));
        // jaVA
        System.out.println(convertHalf("ABCDE")); // odd length
        // abCDE (middle goes to upper half)
    }

    public static String convertHalf(String s) {
        if (s == null || s.isEmpty()) return s;
        int mid = s.length() / 2;
        String firstHalf  = s.substring(0, mid).toLowerCase();
        String secondHalf = s.substring(mid).toUpperCase();
        return firstHalf + secondHalf;
    }

    // Java 8 Stream approach
    public static String convertHalfStream(String s) {
        int mid = s.length() / 2;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            sb.append(i < mid
                ? Character.toLowerCase(c)
                : Character.toUpperCase(c));
        }
        return sb.toString();
    }

    // Test
    // "HelloWorld" (length=10, mid=5)
    // First half (0-4): "Hello" -> "hello"
    // Second half (5-9): "World" -> "WORLD"
    // Result: "helloWORLD"

    // "Java" (length=4, mid=2)
    // First half (0-1): "Ja" -> "ja"
    // Second half (2-3): "va" -> "VA"
    // Result: "jaVA"
}

import java.util.*;
import java.util.stream.*;

public class HighestPaidByDept {
    record Employee(String name, String dept, double salary) {}

    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee("Alice",   "Engineering", 120000),
            new Employee("Bob",     "Engineering",  95000),
            new Employee("Carol",   "Marketing",    80000),
            new Employee("Dave",    "Marketing",    85000),
            new Employee("Eve",     "HR",            70000),
            new Employee("Frank",   "Engineering", 130000)
        );

        // Approach 1: groupingBy + maxBy
        Map<String, Optional<Employee>> highestPaid = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::dept,
                Collectors.maxBy(
                    Comparator.comparingDouble(Employee::salary))));

        highestPaid.forEach((dept, emp) ->
            emp.ifPresent(e ->
                System.out.printf("%s: %s (%.0f)%n",
                    dept, e.name(), e.salary())));
        // Engineering: Frank (130000)
        // Marketing: Dave (85000)
        // HR: Eve (70000)

        // Approach 2: collectingAndThen to unwrap Optional
        Map<String, Employee> highestPaidNoOpt = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::dept,
                Collectors.collectingAndThen(
                    Collectors.maxBy(
                        Comparator.comparingDouble(Employee::salary)),
                    Optional::get)));

        highestPaidNoOpt.forEach((dept, emp) ->
            System.out.printf("%s -> %s: %.0f%n",
                dept, emp.name(), emp.salary()));

        // Approach 3: toMap with merge function
        Map<String, Employee> highestPaid3 = employees.stream()
            .collect(Collectors.toMap(
                Employee::dept,
                e -> e,
                (e1, e2) -> e1.salary() > e2.salary() ? e1 : e2));
    }
}

import java.util.*;
import java.util.stream.*;

public class VowelStartWords {
    public static void main(String[] args) {
        List<String> words = Arrays.asList(
            "apple", "banana", "orange", "grape",
            "umbrella", "cherry", "Elephant", "mango",
            "ice", "Java", "avocado"
        );

        Set<Character> vowels = Set.of('a','e','i','o','u');

        // Approach 1: Character check
        List<String> vowelWords = words.stream()
            .filter(w -> !w.isEmpty() &&
                vowels.contains(Character.toLowerCase(w.charAt(0))))
            .collect(Collectors.toList());
        System.out.println(vowelWords);
        // [apple, orange, umbrella, Elephant, ice, avocado]

        // Approach 2: Regex
        List<String> vowelWordsRegex = words.stream()
            .filter(w -> w.matches("^[aeiouAEIOU].*"))
            .collect(Collectors.toList());
        System.out.println(vowelWordsRegex);

        // Approach 3: String method
        List<String> vowelWordsStr = words.stream()
            .filter(w -> "aeiouAEIOU"
                .indexOf(w.charAt(0)) != -1)
            .collect(Collectors.toList());
        System.out.println(vowelWordsStr);

        // Count
        long count = words.stream()
            .filter(w -> vowels.contains(
                Character.toLowerCase(w.charAt(0))))
            .count();
        System.out.println("Vowel-starting words: " + count); // 6

        // Group by first letter
        Map<Character, List<String>> byFirstLetter = words.stream()
            .collect(Collectors.groupingBy(
                w -> Character.toLowerCase(w.charAt(0))));
        System.out.println(byFirstLetter);
    }
}

