public class EmployeeCountByDept {
    record Employee(String name, String department, double salary) {}

    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee("Alice",  "Engineering", 100000),
            new Employee("Bob",    "Engineering",  95000),
            new Employee("Carol",  "Marketing",    80000),
            new Employee("Dave",   "HR",            70000),
            new Employee("Eve",    "Engineering", 120000),
            new Employee("Frank",  "Marketing",    85000),
            new Employee("Grace",  "HR",            72000)
        );

        // Count by department
        Map<String, Long> countByDept = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::department,
                Collectors.counting()));

        System.out.println("Employee count by department:");
        countByDept.forEach((dept, count) ->
            System.out.printf("  %s: %d%n", dept, count));
        // Engineering: 3
        // Marketing: 2
        // HR: 2

        // Sorted by count descending
        countByDept.entrySet().stream()
            .sorted(Map.Entry.<String, Long>comparingByValue()
                .reversed())
            .forEach(e ->
                System.out.printf("%s -> %d employees%n",
                    e.getKey(), e.getValue()));
        // Engineering -> 3 employees
        // Marketing -> 2 employees
        // HR -> 2 employees

        // As a TreeMap (sorted by department name alphabetically)
        Map<String, Long> sortedByDept = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::department,
                TreeMap::new,
                Collectors.counting()));
        System.out.println(sortedByDept);
        // {Engineering=3, HR=2, Marketing=2}
    }
}

